package org.apache.kafka.streams.fray;

/**
 * Fray test for the setState() deadlock bug.
 *
 * Bug: KafkaStreams.setState() used to call stateListener.onChange() INSIDE
 * synchronized(stateLock). This creates a deadlock when:
 *   - Thread A (close caller): holds 'this' monitor → waits on stateLock
 *   - Thread B (shutdown thread): holds stateLock → callback tries to acquire 'this'
 *
 * This test reproduces the exact lock pattern. With the bug, Fray finds a deadlock.
 * With the fix (callback outside stateLock), no deadlock is possible.
 */
public class SetStateDeadlockTest {

    private final Object stateLock = new Object();
    private volatile int state = 0; // 0=CREATED, 1=RUNNING, 2=PENDING_SHUTDOWN, 3=NOT_RUNNING
    private volatile Runnable stateListener = null;

    /** Mimics KafkaStreams.setState() — fixed version calls listener outside lock */
    private boolean setState(int newState) {
        synchronized (stateLock) {
            state = newState;
            stateLock.notifyAll();
        }
        // Fixed: listener called OUTSIDE the lock
        if (stateListener != null) {
            stateListener.run();
        }
        return true;
    }

    /** Mimics KafkaStreams.close() — synchronized on 'this' */
    public synchronized boolean close() {
        setState(2); // PENDING_SHUTDOWN

        // Start "shutdown thread" that will eventually set NOT_RUNNING
        Thread shutdownThread = new Thread(() -> {
            setState(3); // NOT_RUNNING — listener runs outside stateLock
        });
        shutdownThread.start();

        // Wait for NOT_RUNNING
        synchronized (stateLock) {
            while (state != 3) {
                try {
                    stateLock.wait();
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    return false;
                }
            }
        }
        return true;
    }

    /** Mimics a synchronized method that could be called from user callback */
    public synchronized String getInfo() {
        return "state=" + state;
    }

    public static void main(String[] args) throws Exception {
        SetStateDeadlockTest instance = new SetStateDeadlockTest();

        // The user's state listener calls a synchronized method on the instance.
        // With the bug (callback inside stateLock), this deadlocks.
        // With the fix (callback outside stateLock), this is safe.
        instance.stateListener = instance::getInfo;
        instance.state = 1; // RUNNING

        Thread closeThread = new Thread(instance::close);
        closeThread.start();
        closeThread.join();
    }
}

