package org.apache.kafka.streams.fray;

import java.util.concurrent.locks.Condition;
import java.util.concurrent.locks.ReentrantLock;
import java.util.concurrent.atomic.AtomicBoolean;

/**
 * Fray test for the removeStreamThread() lost-wakeup hang.
 *
 * Bug: removeStreamThread() calls shutdown() on a StreamThread but does NOT call
 * topologyMetadata.wakeupThreads(). If the thread is blocked in
 * maybeWaitForNonEmptyTopology() (awaiting on topologyCV), it never wakes up
 * to see its state changed to PENDING_SHUTDOWN, causing an indefinite hang.
 *
 * Fix: After calling shutdown(), also call wakeupThreads() to signal topologyCV.
 *
 * This test reproduces the exact pattern with the fix applied.
 */
public class RemoveThreadHangTest {

    private final ReentrantLock topologyLock = new ReentrantLock();
    private final Condition topologyCV = topologyLock.newCondition();
    private final AtomicBoolean topologyEmpty = new AtomicBoolean(true);
    private final AtomicBoolean threadAlive = new AtomicBoolean(true);
    private volatile boolean threadExited = false;

    /** Mimics TopologyMetadata.maybeWaitForNonEmptyTopology() */
    private void maybeWaitForNonEmptyTopology() {
        if (topologyEmpty.get() && threadAlive.get()) {
            topologyLock.lock();
            try {
                while (topologyEmpty.get() && threadAlive.get()) {
                    try {
                        topologyCV.await();
                    } catch (InterruptedException e) {
                        Thread.currentThread().interrupt();
                        return;
                    }
                }
            } finally {
                topologyLock.unlock();
            }
        }
    }

    /** Mimics TopologyMetadata.wakeupThreads() */
    private void wakeupThreads() {
        topologyLock.lock();
        try {
            topologyCV.signalAll();
        } finally {
            topologyLock.unlock();
        }
    }

    /** Mimics StreamThread.shutdown() */
    private void shutdownThread() {
        threadAlive.set(false);
    }

    /**
     * Mimics removeStreamThread() — fixed version calls wakeupThreads() after shutdown.
     * Without the wakeupThreads() call, the worker thread hangs in await() forever.
     */
    private void removeStreamThread() {
        shutdownThread();
        wakeupThreads(); // Fix: signal the condition so waiting thread can re-check
    }

    /** Mimics the StreamThread's run loop waiting on empty topology */
    private void workerThreadRun() {
        maybeWaitForNonEmptyTopology();
        threadExited = true;
    }

    public static void main(String[] args) throws Exception {
        RemoveThreadHangTest instance = new RemoveThreadHangTest();

        // Worker thread blocks on empty topology
        Thread worker = new Thread(instance::workerThreadRun);
        worker.start();

        // Another thread removes (shuts down) the worker
        Thread remover = new Thread(instance::removeStreamThread);
        remover.start();

        remover.join();
        worker.join();

        if (!instance.threadExited) {
            throw new AssertionError("Worker thread did not exit — lost wakeup!");
        }
    }
}

